void VCvtF32Bf8Vop3::execute_impl(amdgpu::Wavefront &wf) {
  uint64_t exec = wf.exec();
  for (uint32_t lane = 0; lane < wf.wf_size(); ++lane) {
    if (!(exec & (1ULL << lane)))
      continue;
    uint32_t src_byte = (src0.read_lane(wf, lane) >> ((((amdgpu::vop3_opsel(inst_) & 0x1u) << 1) |
                                                       ((amdgpu::vop3_opsel(inst_) & 0x2u) >> 1)) *
                                                      8u)) &
                        0xFFu;
    vdst.write_lane(
        wf, lane,
        std::bit_cast<uint32_t>(util::bf8_e5m2_fnuz_to_f32(static_cast<uint8_t>(src_byte))));
  }
}

VCvtPkF32Fp8Vop3::VCvtPkF32Fp8Vop3(const MachineInst *inst)
    : Vop3("v_cvt_pk_f32_fp8", reinterpret_cast<const OpEncoding *>(inst),
           make_exec_fn<VCvtPkF32Fp8Vop3>()),
      vdst(64, OperandType::OPR_VGPR, reinterpret_cast<const OpEncoding *>(inst)->vdst),
      src0(16, OperandType::OPR_SRC_NOLIT, reinterpret_cast<const OpEncoding *>(inst)->src0) {
  dst_operands_[0] = &vdst;
  src_operands_[0] = &src0;
  num_src_ = 1;
  num_dst_ = 1;
}

void VCvtPkF32Fp8Vop3::execute_impl(amdgpu::Wavefront &wf) {
  uint64_t exec = wf.exec();
  for (uint32_t lane = 0; lane < wf.wf_size(); ++lane) {
    if (!(exec & (1ULL << lane)))
      continue;
    uint32_t packed = src0.read_lane(wf, lane);
    bool src_hi = inst_.op_sel & 1;
    uint32_t half = src_hi ? (packed >> 16) : (packed & 0xFFFFu);
    float lo = util::fp8_e4m3_fnuz_to_f32(static_cast<uint8_t>(half & 0xFFu));
    float hi = util::fp8_e4m3_fnuz_to_f32(static_cast<uint8_t>((half >> 8) & 0xFFu));
    uint32_t lo_bits = std::bit_cast<uint32_t>(lo);
    uint32_t hi_bits = std::bit_cast<uint32_t>(hi);
    vdst.write_lane64(wf, lane,
                      static_cast<uint64_t>(lo_bits) | (static_cast<uint64_t>(hi_bits) << 32));
  }
}

