void VCmpxFI32Vop3::execute_impl(amdgpu::Wavefront &wf) {
  uint64_t exec = wf.exec();
  uint64_t result = 0;
  for (uint32_t lane = 0; lane < wf.wf_size(); ++lane) {
    if (!(exec & (1ULL << lane)))
      continue;
    (void)lane;
  }
  if (wf.wf_size() <= 32)
    vdst.write_scalar(wf, static_cast<uint32_t>(result));
  else
    vdst.write_scalar64(wf, result);
  wf.set_exec(result);
}

